const capacity = 12;
const minLoad = capacity * 0.25;
const eff = 52;
const renewable = [3,8,14,11,5,2];
const gridPrice = [28,31,65,94,72,40];
const h2Price = 5.80;
const kgPerMWh = 1000/eff;
const thresholdGridPrice = h2Price * 1000 / eff;
let rows = [];
let cum = {cost:0, revenue:0, margin:0, curtMWh:0};
for(let i=0;i<renewable.length;i++) {
  const ren = renewable[i];
  const gp = gridPrice[i];
  const gridPurch = Math.max(0, capacity - Math.min(ren, capacity));
  const dispatch = Math.min(capacity, ren + gridPurch);
  const h2 = dispatch * kgPerMWh;
  const cost = gridPurch * gp;
  const revenue = h2 * h2Price;
  const margin = revenue - cost;
  rows.push({hour:i+1, ren, gp, dispatch, gridPurch, h2, cost, revenue, margin});
  cum.cost += cost; cum.revenue += revenue; cum.margin += margin; cum.curtMWh += Math.max(0, ren - dispatch);
}
console.table(rows);
console.log({capacity,minLoad,kgPerMWh,thresholdGridPrice,cum});
NODE"}

